class Solution:
    def validArrangement(self, pairs: List[List[int]]) -> List[List[int]]:
        graph = {}
        for pair in pairs:
            if pair[1] not in graph:
                graph[pair[1]] = []
            graph[pair[1]].append(pair[0])
        res = []
        def dfs(node):
            while node in graph and graph[node]:
                dfs(graph[node].pop())
            res.append([node, node])
            for pair in pairs:
                if pair[0] == node:
                    res[-1][1] = pair[1]
                    break
        dfs(pairs[0][1])
        return res[::-1]
